import { useState } from 'react';
import { Controller, useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { ShieldCheck, AlertTriangle, X } from 'lucide-react';
import { Button } from '@/components/common/Button';
import { DOBPicker } from '@/components/common/DOBPicker';
import type { DateOfBirth } from '@/components/common/DOBPicker';
import { useAuth } from '@/contexts/AuthContext';

// Helper to check if DOB makes user 18+
const isAdultFromDOB = (dob: DateOfBirth | null): boolean => {
  if (!dob || !dob.year || !dob.month || !dob.day) return false;

  const today = new Date();
  const birthDate = new Date(dob.year, dob.month - 1, dob.day);
  let age = today.getFullYear() - birthDate.getFullYear();
  const monthDiff = today.getMonth() - birthDate.getMonth();

  if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) {
    age--;
  }

  return age >= 18;
};

const dobSchema = z.object({
  dateOfBirth: z.object({
    month: z.number().min(1, 'Month is required').max(12),
    day: z.number().min(1, 'Day is required').max(31),
    year: z.number().min(1900, 'Year is required').max(new Date().getFullYear() - 18),
  }).refine((dob) => isAdultFromDOB(dob), {
    message: 'You must be at least 18 years old to use this service',
  }),
  ageConsent: z.boolean().refine((val) => val === true, {
    message: 'You must confirm that you are 18 years or older',
  }),
});

type DOBFormData = z.infer<typeof dobSchema>;

interface DOBCollectionModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export function DOBCollectionModal({ isOpen, onClose }: DOBCollectionModalProps) {
  const { completeRegistration, logout } = useAuth();
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const {
    control,
    handleSubmit,
    watch,
    formState: { errors },
  } = useForm<DOBFormData>({
    resolver: zodResolver(dobSchema),
    defaultValues: {
      dateOfBirth: { month: 0, day: 0, year: 0 },
      ageConsent: false,
    },
  });

  const dateOfBirth = watch('dateOfBirth');
  const ageConsent = watch('ageConsent');
  const isAdult = isAdultFromDOB(dateOfBirth);

  const onSubmit = async (data: DOBFormData) => {
    setError('');
    setLoading(true);

    try {
      await completeRegistration(data.dateOfBirth, data.ageConsent);
      onClose();
    } catch (err: any) {
      console.error('Complete registration error:', err);
      if (err.response?.status === 403) {
        setError('You must be at least 18 years old to use this service.');
      } else if (err.response?.data?.detail) {
        setError(err.response.data.detail);
      } else {
        setError('Failed to complete registration. Please try again.');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = async () => {
    // If user cancels, log them out since they can't use the service without age verification
    await logout();
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm">
      <div className="relative max-w-md w-full bg-zinc-900 rounded-2xl p-6 border border-zinc-800 shadow-xl">
        {/* Close button */}
        <button
          onClick={handleCancel}
          className="absolute top-4 right-4 text-zinc-400 hover:text-white transition-colors"
          aria-label="Close"
        >
          <X className="w-5 h-5" />
        </button>

        {/* Header */}
        <div className="text-center mb-6">
          <div className="flex justify-center mb-4">
            <ShieldCheck className="w-12 h-12 text-primary-500" />
          </div>
          <h2 className="text-xl font-bold text-white mb-2">
            Age Verification Required
          </h2>
          <p className="text-sm text-zinc-400">
            To complete your account setup, please provide your date of birth.
          </p>
        </div>

        {/* Warning */}
        <div className="flex items-start gap-3 text-amber-500/90 bg-amber-500/10 p-3 rounded-lg text-xs leading-relaxed mb-6">
          <AlertTriangle className="shrink-0 w-4 h-4 mt-0.5" />
          <p>
            <span className="font-medium">18+ Only:</span> This service contains age-restricted content. You must be 18 or older to continue.
          </p>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
          {error && (
            <div className="bg-red-500/10 border border-red-500/50 text-red-500 px-4 py-3 rounded-lg text-sm">
              {error}
            </div>
          )}

          <Controller
            name="dateOfBirth"
            control={control}
            render={({ field }) => (
              <DOBPicker
                label="Date of Birth"
                value={field.value ?? null}
                onChange={field.onChange}
                error={errors.dateOfBirth?.message || errors.dateOfBirth?.root?.message}
                disabled={loading}
              />
            )}
          />

          {!isAdult && dateOfBirth && (dateOfBirth.month > 0 || dateOfBirth.day > 0 || dateOfBirth.year > 0) && (
            <p className="text-xs text-red-400 text-center">
              You must be at least 18 years old to use this service
            </p>
          )}

          {/* Age Consent Checkbox */}
          <Controller
            name="ageConsent"
            control={control}
            render={({ field }) => (
              <div className="space-y-1">
                <label className="flex items-start gap-3 cursor-pointer group">
                  <input
                    type="checkbox"
                    checked={field.value}
                    onChange={field.onChange}
                    disabled={loading}
                    className="mt-0.5 w-5 h-5 rounded border-2 border-zinc-700 bg-zinc-900 text-primary-500 focus:ring-2 focus:ring-primary-500 focus:ring-offset-2 focus:ring-offset-zinc-900 disabled:opacity-50 disabled:cursor-not-allowed transition-all cursor-pointer"
                  />
                  <span className="text-sm text-zinc-300 group-hover:text-white transition-colors">
                    I confirm that I am <span className="font-semibold text-white">18 years or older</span> and agree to the Terms of Service
                  </span>
                </label>
                {errors.ageConsent && (
                  <p className="text-xs text-red-400 ml-8">
                    {errors.ageConsent.message}
                  </p>
                )}
              </div>
            )}
          />

          <div className="flex gap-3">
            <Button
              type="button"
              variant="secondary"
              className="flex-1"
              onClick={handleCancel}
              disabled={loading}
            >
              Cancel
            </Button>
            <Button
              type="submit"
              variant="primary"
              className="flex-1"
              loading={loading}
              disabled={loading || !isAdult || !ageConsent}
            >
              Continue
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
}

/**
 * MarkdownView Component
 *
 * Renders Markdown content with proper styling using @tailwindcss/typography.
 */

import React from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';

interface MarkdownViewProps {
  content: string;
  className?: string;
}

export const MarkdownView: React.FC<MarkdownViewProps> = ({ content, className = '' }) => {
  return (
    <div className={`prose prose-slate max-w-none ${className}`}>
      <ReactMarkdown
        remarkPlugins={[remarkGfm]}
        components={{
          // Custom rendering for images to handle lazy loading
          img: ({ node, ...props }) => (
            <img
              {...props}
              loading="lazy"
              className="rounded-lg shadow-md"
              alt={props.alt || 'Blog image'}
            />
          ),
          // Custom rendering for links to open in new tab
          a: ({ node, ...props }) => (
            <a
              {...props}
              target="_blank"
              rel="noopener noreferrer"
              className="text-pink-600 hover:text-pink-700 underline"
            />
          ),
          // Custom rendering for code blocks
          code: ({ className, children, ...props }) => {
            return (
              <code
                className={className || "bg-gray-100 text-pink-600 px-1 py-0.5 rounded text-sm"}
                {...props}
              >
                {children}
              </code>
            );
          },
          // Custom rendering for pre blocks
          pre: ({ children }) => (
            <pre className="bg-gray-900 text-gray-100 p-4 rounded-lg overflow-x-auto">
              {children}
            </pre>
          ),
        }}
      >
        {content}
      </ReactMarkdown>
    </div>
  );
};

import { useState, useEffect } from 'react';
import { useWizard } from '@/contexts/CharacterWizardContext';
import { WizardStep } from '../WizardStep';
import { Input, Button } from '@/components/common';
import { Sparkles, Image as ImageIcon, Loader2 } from 'lucide-react';
import { api } from '@/services/api';

const raceOptions: { value: string; label: string }[] = [
  { value: 'white race', label: 'White' },
  { value: 'black race', label: 'Black' },
  { value: 'yellow race', label: 'Asian' },
];

export function Step9Confirm() {
  const { characterData, updateNestedField, updateField } = useWizard();
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedOptions, setGeneratedOptions] = useState<string[]>([]);
  const [hasAutoGenerated, setHasAutoGenerated] = useState(false);

  const handleAgeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    const age = value === '' ? undefined : parseInt(value, 10);
    updateNestedField('identity.age', age);
  };

  const isAgeValid =
    characterData.identity.age !== undefined &&
    characterData.identity.age >= 18 &&
    characterData.identity.age <= 99;

  const handleGenerateAvatar = async () => {
    setIsGenerating(true);
    try {
      const promptParts = [
        'Best quality, masterpiece',
        characterData.gender === 'Male' ? '1boy, male' : '1girl, female',
        characterData.style || 'Realistic',
        characterData.identity.age ? `${characterData.identity.age} years old` : '',
        characterData.appearance.bodyType,
        characterData.appearance.skinTone ? `${characterData.appearance.skinTone} skin` : '',
        characterData.hair.color ? `${characterData.hair.color} hair` : '',
        characterData.hair.style ? `${characterData.hair.style} hair` : '',
        characterData.face.eyeColor ? `${characterData.face.eyeColor} eyes` : '',
        characterData.face.lipColor ? `${characterData.face.lipColor} lips` : '',
        characterData.personality.tags.length > 0 ? `${characterData.personality.tags.join(', ')} expression` : '',
        characterData.outfit.style ? `wearing ${characterData.outfit.style}` : '',
        characterData.outfit.description,
        'looking at viewer, portrait',
      ];
      const prompt = promptParts.filter(Boolean).join(', ');

      const response = await api.post('/images/generate-batch', { prompt, count: 2 });
      if (response.data.success && response.data.image_urls && response.data.image_urls.length > 0) {
        setGeneratedOptions((prev) => [...prev, ...response.data.image_urls]);
        if (!characterData.avatarUrl) {
          updateField('avatarUrl', response.data.image_urls[0]);
        }
      }
    } catch (error) {
      console.error('Failed to generate avatar', error);
    } finally {
      setIsGenerating(false);
    }
  };

  useEffect(() => {
    if (!characterData.avatarUrl && !isGenerating && !hasAutoGenerated) {
      setHasAutoGenerated(true);
      handleGenerateAvatar();
    }
  }, []);

  const selectAvatar = (url: string) => {
    updateField('avatarUrl', url);
  };

  return (
    <WizardStep
      title="Confirm and Finish"
      description="Name your character and generate a final avatar"
    >
      <div className="space-y-8">
        <div>
          <Input
            label="Character Name"
            placeholder="e.g., Emma, Sophia, Olivia"
            value={characterData.identity.firstName || ''}
            onChange={(e) => updateNestedField('identity.firstName', e.target.value)}
            helperText="Choose a name that fits your character"
          />
        </div>

        <div>
          <Input
            label="Age"
            type="number"
            min={18}
            max={99}
            placeholder="18-99"
            value={characterData.identity.age?.toString() || ''}
            onChange={handleAgeChange}
            error={
              characterData.identity.age !== undefined && !isAgeValid
                ? 'Age must be between 18 and 99'
                : undefined
            }
            helperText="Character must be 18 or older"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-zinc-300 mb-2">
            Race (Optional)
          </label>
          <select
            value={characterData.identity.race || ''}
            onChange={(e) => updateNestedField('identity.race', e.target.value || undefined)}
            className="w-full px-4 py-3 bg-white/5 border border-white/10 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-primary-500"
          >
            <option value="">Select race (optional)</option>
            {raceOptions.map((option) => (
              <option key={option.value} value={option.value}>
                {option.label}
              </option>
            ))}
          </select>
          <p className="text-xs text-zinc-500 mt-1">
            This helps with generating accurate character images.
          </p>
        </div>

        <div>
          <div className="flex items-center gap-2 mb-4">
            <ImageIcon size={20} className="text-primary-500" />
            <h3 className="text-lg font-semibold">Avatar</h3>
          </div>

          <div className="flex flex-col items-center gap-4 p-6 rounded-lg glass-effect border border-white/10">
            {generatedOptions.length > 0 ? (
              <div className="grid grid-cols-3 gap-4 w-full">
                {generatedOptions.map((url, index) => (
                  <div
                    key={index}
                    onClick={() => selectAvatar(url)}
                    className={`relative aspect-square rounded-xl overflow-hidden cursor-pointer transition-all ${
                      characterData.avatarUrl === url
                        ? 'border-4 border-primary-500 scale-105 shadow-lg shadow-primary-500/20'
                        : 'border border-white/10 hover:border-white/30 hover:scale-105'
                    }`}
                  >
                    <img src={url} alt={`Option ${index + 1}`} className="w-full h-full object-cover" />
                    {characterData.avatarUrl === url && (
                      <div className="absolute top-2 right-2 bg-primary-500 text-white rounded-full p-1">
                        <Sparkles size={12} />
                      </div>
                    )}
                  </div>
                ))}
              </div>
            ) : characterData.avatarUrl ? (
              <div className="relative w-64 h-64 rounded-xl overflow-hidden border-2 border-primary-500">
                <img src={characterData.avatarUrl} alt="Generated Avatar" className="w-full h-full object-cover" />
              </div>
            ) : (
              <div className="w-64 h-64 rounded-xl bg-white/5 flex items-center justify-center border border-white/10">
                <p className="text-zinc-500 text-sm">No avatar generated</p>
              </div>
            )}

            <Button
              onClick={handleGenerateAvatar}
              disabled={isGenerating}
              className="w-full max-w-xs flex items-center justify-center gap-2 mt-4"
            >
              {isGenerating ? (
                <>
                  <Loader2 size={18} className="animate-spin" />
                  Generating 2 Options...
                </>
              ) : (
                <>
                  <Sparkles size={18} />
                  {generatedOptions.length > 0 ? 'Regenerate Avatars' : 'Generate Avatars'}
                </>
              )}
            </Button>
          </div>
        </div>

        {characterData.identity.firstName && isAgeValid && (
          <div className="mt-8 p-6 rounded-lg glass-effect border border-primary-500/20">
            <h4 className="text-sm font-semibold text-primary-500 mb-3">
              Character Preview
            </h4>
            <div className="space-y-2 text-sm">
              <p>
                <span className="text-zinc-400">Name:</span>{' '}
                <span className="text-white font-medium">
                  {characterData.identity.firstName}, {characterData.identity.age}
                </span>
              </p>
              <p>
                <span className="text-zinc-400">Style:</span>{' '}
                <span className="text-white">{characterData.style}</span>
              </p>
              <p>
                <span className="text-zinc-400">Personality:</span>{' '}
                <span className="text-white">
                  {characterData.personality.tags.join(', ')}
                </span>
              </p>
              <p>
                <span className="text-zinc-400">Relationship:</span>{' '}
                <span className="text-white">
                  {characterData.personality.relationship}
                </span>
              </p>
              {characterData.background.profession && (
                <p>
                  <span className="text-zinc-400">Profession:</span>{' '}
                  <span className="text-white">
                    {characterData.background.profession}
                  </span>
                </p>
              )}
            </div>
          </div>
        )}

        <div className="text-center p-6 rounded-lg bg-gradient-primary/10 border border-primary-500/30">
          <p className="text-zinc-200">
            You are all set. Click "Create Character" to bring your AI companion to life.
          </p>
        </div>
      </div>
    </WizardStep>
  );
}

