import { useState, useEffect, useRef } from 'react';
import Vapi from '@vapi-ai/web';
import { api } from '@/services/api';
import { Button } from '@/components/common';
import { X, Mic, MicOff, Phone, Volume2, Loader2 } from 'lucide-react';
import type { Character } from '@/types';

interface VoiceCallModalProps {
  isOpen: boolean;
  onClose: () => void;
  character: Character;
  sessionId: string | null;
  onCallEnd?: (duration: number, cost: number) => void;
}

type CallState = 'idle' | 'connecting' | 'active' | 'ended' | 'error';

export function VoiceCallModal({
  isOpen,
  onClose,
  character,
  sessionId,
  onCallEnd
}: VoiceCallModalProps) {
  const [callState, setCallState] = useState<CallState>('idle');
  const [duration, setDuration] = useState(0);
  const [isMuted, setIsMuted] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [_assistantId, setAssistantId] = useState<string>('');
  const [_activeSessionId, setActiveSessionId] = useState<string>('');
  const [_estimatedCost, setEstimatedCost] = useState(0);
  const [transcripts, setTranscripts] = useState<Array<{role: string, text: string, timestamp: number}>>([]);
  const [finalDuration, setFinalDuration] = useState(0);
  const [finalCost, setFinalCost] = useState(0);

  // Avatar state for video playback
  const [avatarState, setAvatarState] = useState<'idle' | 'talking'>('idle');
  const talkingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const vapiRef = useRef<Vapi | null>(null);
  const startTimeRef = useRef<number>(0);
  const assistantIdRef = useRef<string>('');
  const sessionIdRef = useRef<string>('');
  const transcriptsRef = useRef<Array<{role: string, text: string, timestamp: number}>>([]);
  const transcriptEndRef = useRef<HTMLDivElement>(null);

  // Format duration as MM:SS
  const formatDuration = (seconds: number): string => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  // Calculate real-time cost
  const calculateCost = (seconds: number): number => {
    const minutes = Math.ceil(seconds / 60);
    return minutes * 10; // 10 credits per minute
  };

  // Start voice call
  const startCall = async () => {
    setCallState('connecting');
    setError(null);

    try {
      // 1. Call backend to create assistant
      const response = await api.post('/chat/voice/start', null, {
        params: {
          character_id: character.id,
          session_id: sessionId
        }
      });

      const {
        assistant_id,
        client_token,
        session_id: newSessionId,
        estimated_cost_per_minute
      } = response.data;

      setAssistantId(assistant_id);
      setActiveSessionId(newSessionId);
      setEstimatedCost(estimated_cost_per_minute);

      // Store in refs for reliable access during cleanup
      assistantIdRef.current = assistant_id;
      sessionIdRef.current = newSessionId;

      // 2. Initialize Vapi with public key
      // Note: client_token is actually the Vapi public key
      const vapi = new Vapi(client_token);
      vapiRef.current = vapi;

      console.log('Initializing Vapi with assistant:', assistant_id);

      // 3. Event listeners
      vapi.on('call-start', () => {
        console.log('✅ Call started successfully');
        setCallState('active');
      });

      vapi.on('call-end', () => {
        console.log('Call ended');
        handleCallEnd();
      });

      vapi.on('speech-start', () => {
        console.log('User started speaking');
        // User interrupted or started speaking, switch to idle immediately
        setAvatarState('idle');
        if (talkingTimeoutRef.current) {
          clearTimeout(talkingTimeoutRef.current);
          talkingTimeoutRef.current = null;
        }
      });

      vapi.on('speech-end', () => {
        console.log('User stopped speaking');
      });

      vapi.on('error', (err: any) => {
        console.error('Vapi error:', err);
        setError(err.message || 'An error occurred during the call');
        setCallState('error');
      });

      vapi.on('message', (message: any) => {
        console.log('Vapi message:', message);

        // Handle transcript events
        if (message.type === 'transcript' && (message.transcript || message.text)) {
          const text = message.transcript || message.text;
          const role = message.role || 'user';

          // Handle avatar state for assistant speech
          if (role === 'assistant') {
            setAvatarState('talking');

            // Clear existing timeout
            if (talkingTimeoutRef.current) {
              clearTimeout(talkingTimeoutRef.current);
            }

            // Set timeout to revert to idle if no more text comes in
            talkingTimeoutRef.current = setTimeout(() => {
              setAvatarState('idle');
            }, 1000); // 1 second silence = stop talking animation
          }

          if (text) {
            const newTranscript = {
              role: role,
              text: text,
              timestamp: Date.now()
            };

            transcriptsRef.current = [...transcriptsRef.current, newTranscript];
            setTranscripts(prev => [...prev, newTranscript]);
          }
        }
      });

      // 4. Start call
      await vapi.start(assistant_id);

    } catch (err: any) {
      console.error('Failed to start call:', err);

      // Handle insufficient credits error
      if (err.response?.status === 402) {
        const detail = err.response.data.detail;
        if (typeof detail === 'object' && detail.error === 'insufficient_credits') {
          setError(`Insufficient credits. You need ${detail.required} credits (current: ${detail.current})`);
        } else {
          setError('Insufficient credits for voice call');
        }
      } else {
        setError(err.response?.data?.detail || 'Failed to start voice call. Please try again.');
      }

      setCallState('error');
    }
  };

  // End call
  const endCall = async () => {
    if (vapiRef.current) {
      await vapiRef.current.stop();
    }
  };

  // Handle call end (cleanup and billing)
  const handleCallEnd = async () => {
    // Calculate actual duration from timestamps (more reliable than timer state)
    const calculatedDuration = Math.max(0, Math.floor((Date.now() - startTimeRef.current) / 1000));
    const finalAssistantId = assistantIdRef.current;
    const finalSessionId = sessionIdRef.current;

    // Store final duration and cost for display
    setFinalDuration(calculatedDuration);
    const calculatedCost = calculateCost(calculatedDuration);
    setFinalCost(calculatedCost);

    setCallState('ended');

    console.log('Ending call:', {
      duration: calculatedDuration,
      assistant_id: finalAssistantId,
      session_id: finalSessionId
    });

    try {
      // Validate we have required data
      if (!finalAssistantId || !finalSessionId) {
        console.error('Missing required data for billing:', {
          assistant_id: finalAssistantId,
          session_id: finalSessionId
        });
        setError('Call ended but missing billing information');
        setTimeout(() => onClose(), 2000);
        return;
      }

      // Call backend to process billing and save transcripts
      const response = await api.post('/chat/voice/end', {
        assistant_id: finalAssistantId,
        session_id: finalSessionId,
        duration_seconds: calculatedDuration,
        transcripts: transcriptsRef.current
      });

      const { credits_deducted } = response.data;

      console.log(`Call ended. Duration: ${calculatedDuration}s, Credits deducted: ${credits_deducted}`);

      // Notify parent
      if (onCallEnd) {
        onCallEnd(calculatedDuration, credits_deducted);
      }

      // Close modal after 2 seconds
      setTimeout(() => {
        onClose();
      }, 2000);

    } catch (err: any) {
      console.error('Failed to end call:', err);
      setError('Call ended but failed to process billing');
      setTimeout(() => onClose(), 3000);
    }
  };

  // Toggle mute
  const toggleMute = () => {
    if (vapiRef.current) {
      vapiRef.current.setMuted(!isMuted);
      setIsMuted(!isMuted);
    }
  };

  // Reset state when modal opens
  useEffect(() => {
    if (isOpen) {
      // Reset all state for new call
      setCallState('idle');
      setDuration(0);
      setIsMuted(false);
      setError(null);
      setAssistantId('');
      setActiveSessionId('');
      setEstimatedCost(0);
      setTranscripts([]);
      setFinalDuration(0);
      setFinalCost(0);
      assistantIdRef.current = '';
      sessionIdRef.current = '';
      startTimeRef.current = 0;
      transcriptsRef.current = [];
    }
  }, [isOpen]);

  // Auto-scroll to latest transcript
  useEffect(() => {
    if (transcriptEndRef.current) {
      transcriptEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [transcripts]);

  // Start timer when call becomes active
  useEffect(() => {
    let intervalId: any;

    if (callState === 'active') {
      console.log('⏰ Starting timer effect');

      // Initialize start time if needed
      if (startTimeRef.current === 0) {
        startTimeRef.current = Date.now();
        console.log('⏰ Set start time to:', new Date(startTimeRef.current).toISOString());
      }

      // Update immediately
      setDuration(Math.floor((Date.now() - startTimeRef.current) / 1000));

      // Start interval
      intervalId = setInterval(() => {
        const elapsed = Math.floor((Date.now() - startTimeRef.current) / 1000);
        setDuration(elapsed);
      }, 1000);
    }

    return () => {
      if (intervalId) {
        clearInterval(intervalId);
        console.log('⏰ Timer effect cleanup');
      }
    };
  }, [callState]);

  // Auto-start on modal open
  useEffect(() => {
    if (isOpen && callState === 'idle') {
      startCall();
    }

    // Cleanup on unmount
    return () => {
      if (talkingTimeoutRef.current) {
        clearTimeout(talkingTimeoutRef.current);
      }
      if (vapiRef.current && callState === 'active') {
        endCall();
      }
    };
  }, [isOpen, callState]);

  // Don't render if not open
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-zinc-900 rounded-2xl max-w-md w-full p-8 relative border border-white/10">
        {/* Close button */}
        <button
          onClick={onClose}
          className="absolute top-4 right-4 text-zinc-400 hover:text-white transition-colors"
        >
          <X size={24} />
        </button>

        {/* Character Avatar or Video */}
        {character.video_url?.IDLE_VIDEO_URL ? (
          <div className="flex flex-col items-center space-y-4 mb-6">
            <div className="relative w-full aspect-[3/4] rounded-xl overflow-hidden bg-black/50 border border-white/10 shadow-2xl">
              <video
                src={character.video_url.IDLE_VIDEO_URL}
                className="absolute inset-0 w-full h-full object-cover"
                autoPlay
                loop
                muted
                playsInline
              />
              {character.video_url.TALKING_VIDEO_URL && (
                <video
                  src={character.video_url.TALKING_VIDEO_URL}
                  className={`absolute inset-0 w-full h-full object-cover transition-opacity duration-200 ${
                    avatarState === 'talking' ? 'opacity-100' : 'opacity-0'
                  }`}
                  autoPlay
                  loop
                  muted
                  playsInline
                />
              )}
              <div className="absolute bottom-0 inset-x-0 p-4 bg-gradient-to-t from-black/90 via-black/50 to-transparent">
                <h2 className="text-2xl font-heading font-bold text-white text-center shadow-black drop-shadow-md">
                  {character.first_name}
                </h2>
                <p className="text-sm text-zinc-200 text-center mt-1 font-medium shadow-black drop-shadow-md">
                  {callState === 'connecting' && 'Connecting...'}
                  {callState === 'active' && (avatarState === 'talking' ? 'Speaking...' : 'Listening...')}
                  {callState === 'ended' && 'Call Ended'}
                  {callState === 'error' && 'Call Failed'}
                </p>
              </div>
            </div>
          </div>
        ) : (
          <div className="flex flex-col items-center space-y-4 mb-6">
            <div className="w-24 h-24 rounded-full bg-gradient-primary flex items-center justify-center overflow-hidden">
              {character.profile_image_url ? (
                <img
                  src={character.profile_image_url}
                  alt={character.first_name}
                  className="w-full h-full object-cover"
                />
              ) : (
                <span className="text-3xl font-bold text-white">
                  {character.first_name.charAt(0)}
                </span>
              )}
            </div>

            <div className="text-center">
              <h2 className="text-2xl font-heading font-bold text-white">
                {character.first_name}
              </h2>
              <p className="text-sm text-zinc-400 mt-1">
                {callState === 'connecting' && 'Connecting...'}
                {callState === 'active' && 'Voice Call Active'}
                {callState === 'ended' && 'Call Ended'}
                {callState === 'error' && 'Call Failed'}
              </p>
            </div>
          </div>
        )}

        {/* Error Message */}
        {error && (
          <div className="mb-4 p-3 rounded-lg bg-red-500/10 border border-red-500/50">
            <p className="text-red-500 text-sm text-center">{error}</p>
          </div>
        )}

        {/* Call Info */}
        {callState === 'active' && (
          <div className="space-y-3 mb-6">
            {/* Duration */}
            <div className="flex items-center justify-between p-3 rounded-lg bg-white/5">
              <span className="text-zinc-400 text-sm">Duration</span>
              <span className="text-white font-mono text-lg">
                {formatDuration(duration)}
              </span>
            </div>

            {/* Live Transcript */}
            {transcripts.length > 0 && (
              <div className="p-3 rounded-lg bg-white/5 max-h-48 overflow-y-auto">
                <div className="text-xs text-zinc-400 mb-2 font-semibold">Live Transcript</div>
                <div className="space-y-2">
                  {transcripts.map((t, idx) => (
                    <div key={idx} className="text-sm">
                      <span className={t.role === 'user' ? 'text-primary-400' : 'text-purple-400'}>
                        {t.role === 'user' ? 'You' : character.first_name}:
                      </span>
                      <span className="text-zinc-300 ml-2">{t.text}</span>
                    </div>
                  ))}
                  <div ref={transcriptEndRef} />
                </div>
              </div>
            )}
          </div>
        )}

        {/* Loading State */}
        {callState === 'connecting' && (
          <div className="flex flex-col items-center space-y-4 mb-6">
            <Loader2 className="w-12 h-12 text-primary-500 animate-spin" />
            <p className="text-zinc-400 text-sm">Connecting to {character.first_name}...</p>
          </div>
        )}

        {/* Active Call Animation */}
        {callState === 'active' && (
          <div className="flex items-center justify-center mb-6">
            <div className="relative">
              {/* Pulsing rings */}
              <div className="absolute inset-0 rounded-full bg-primary-500/20 animate-ping"></div>
              <div className="absolute inset-0 rounded-full bg-primary-500/10 animate-pulse"></div>

              {/* Icon */}
              <div className="relative bg-primary-500 p-4 rounded-full">
                <Volume2 className="w-8 h-8 text-white" />
              </div>
            </div>
          </div>
        )}

        {/* Call Ended */}
        {callState === 'ended' && (
          <div className="flex flex-col items-center space-y-2 mb-6 text-center">
            <p className="text-white">Call completed</p>
            <p className="text-zinc-400 text-sm">
              Duration: {formatDuration(finalDuration)}
            </p>
            <p className="text-yellow-500 text-sm">
              Cost: {finalCost} credits
            </p>
          </div>
        )}

        {/* Call Controls */}
        {callState === 'active' && (
          <div className="flex items-center justify-center gap-4">
            {/* Mute Button */}
            <button
              onClick={toggleMute}
              className={`p-4 rounded-full transition-all ${
                isMuted
                  ? 'bg-red-500 text-white'
                  : 'bg-white/10 text-white hover:bg-white/20'
              }`}
              title={isMuted ? 'Unmute' : 'Mute'}
            >
              {isMuted ? <MicOff size={24} /> : <Mic size={24} />}
            </button>

            {/* End Call Button */}
            <button
              onClick={endCall}
              className="p-5 rounded-full bg-red-500 text-white hover:bg-red-600 transition-all"
              title="End Call"
            >
              <Phone size={28} style={{ transform: 'rotate(135deg)' }} />
            </button>
          </div>
        )}

        {/* Error/Connecting State Buttons */}
        {(callState === 'error' || callState === 'connecting') && (
          <div className="flex justify-center">
            <Button
              variant="outline"
              onClick={onClose}
            >
              Close
            </Button>
          </div>
        )}
      </div>
    </div>
  );
}

