/**
 * Tension Meter Component
 * Visual feedback for script progress with animated state transitions
 */
import { useEffect, useState } from 'react';
import { Zap } from 'lucide-react';

type ScriptState = 'Start' | 'Build' | 'Climax' | 'Resolve';

interface TensionMeterProps {
  progress: number; // 0-100
  state: ScriptState;
  showLabel?: boolean;
  size?: 'sm' | 'md' | 'lg';
  className?: string;
}

const STATE_COLORS = {
  Start: {
    bg: 'from-blue-500 to-cyan-500',
    text: 'text-blue-500',
    glow: 'shadow-blue-500/50',
    label: 'Beginning',
  },
  Build: {
    bg: 'from-purple-500 to-pink-500',
    text: 'text-purple-500',
    glow: 'shadow-purple-500/50',
    label: 'Building',
  },
  Climax: {
    bg: 'from-red-500 to-orange-500',
    text: 'text-red-500',
    glow: 'shadow-red-500/50',
    label: 'Peak',
  },
  Resolve: {
    bg: 'from-yellow-500 to-amber-500',
    text: 'text-yellow-500',
    glow: 'shadow-yellow-500/50',
    label: 'Resolution',
  },
};

const SIZE_CLASSES = {
  sm: {
    height: 'h-2',
    text: 'text-xs',
    icon: 12,
  },
  md: {
    height: 'h-3',
    text: 'text-sm',
    icon: 16,
  },
  lg: {
    height: 'h-4',
    text: 'text-base',
    icon: 20,
  },
};

export function TensionMeter({
  progress,
  state,
  showLabel = true,
  size = 'md',
  className = '',
}: TensionMeterProps) {
  const [animatedProgress, setAnimatedProgress] = useState(0);
  const [shouldPulse, setShouldPulse] = useState(false);

  const colors = STATE_COLORS[state];
  const sizeClasses = SIZE_CLASSES[size];

  // Animate progress changes
  useEffect(() => {
    const timeout = setTimeout(() => {
      setAnimatedProgress(progress);
    }, 100);

    return () => clearTimeout(timeout);
  }, [progress]);

  // Pulse animation at milestones (25%, 50%, 75%, 100%)
  useEffect(() => {
    const milestones = [25, 50, 75, 100];
    const lastMilestone = Math.floor(animatedProgress / 25) * 25;
    const currentMilestone = Math.floor(progress / 25) * 25;

    if (currentMilestone > lastMilestone && milestones.includes(currentMilestone)) {
      setShouldPulse(true);
      setTimeout(() => setShouldPulse(false), 1000);
    }
  }, [progress, animatedProgress]);

  return (
    <div className={`space-y-2 ${className}`}>
      {/* Header */}
      {showLabel && (
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Zap
              size={sizeClasses.icon}
              className={`${colors.text} ${shouldPulse ? 'animate-pulse' : ''}`}
            />
            <span className={`font-semibold ${colors.text} ${sizeClasses.text}`}>
              {colors.label}
            </span>
          </div>
          <span className={`font-mono ${sizeClasses.text} text-zinc-400`}>
            {Math.round(progress)}%
          </span>
        </div>
      )}

      {/* Meter Bar */}
      <div className="relative">
        {/* Background track */}
        <div
          className={`w-full ${sizeClasses.height} bg-zinc-800 rounded-full overflow-hidden`}
        >
          {/* Animated progress fill */}
          <div
            className={`h-full bg-gradient-to-r ${colors.bg} rounded-full transition-all duration-500 ease-out relative ${
              shouldPulse ? `shadow-lg ${colors.glow}` : ''
            }`}
            style={{ width: `${animatedProgress}%` }}
          >
            {/* Shimmer effect */}
            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/30 to-transparent animate-shimmer" />
          </div>
        </div>

        {/* Milestone markers */}
        <div className="absolute inset-0 flex justify-between px-[12.5%]">
          {[25, 50, 75].map((milestone) => (
            <div
              key={milestone}
              className={`w-0.5 ${sizeClasses.height} ${
                progress >= milestone ? 'bg-white/30' : 'bg-zinc-700'
              } transition-colors duration-300`}
            />
          ))}
        </div>
      </div>

      {/* State description */}
      {showLabel && size !== 'sm' && (
        <p className="text-xs text-zinc-500 italic">
          {getStateDescription(state, progress)}
        </p>
      )}
    </div>
  );
}

function getStateDescription(state: ScriptState, progress: number): string {
  switch (state) {
    case 'Start':
      return 'The story begins...';
    case 'Build':
      if (progress < 40) {
        return 'Tension is rising...';
      } else if (progress < 60) {
        return 'Stakes are increasing...';
      } else {
        return 'Approaching the peak...';
      }
    case 'Climax':
      return 'The most intense moment...';
    case 'Resolve':
      if (progress < 95) {
        return 'Winding down...';
      } else {
        return 'Nearing completion...';
      }
    default:
      return '';
  }
}

// Add shimmer animation to global styles
const styles = `
@keyframes shimmer {
  0% {
    transform: translateX(-100%);
  }
  100% {
    transform: translateX(100%);
  }
}

.animate-shimmer {
  animation: shimmer 2s infinite;
}
`;

// Inject styles
if (typeof document !== 'undefined') {
  const existingStyle = document.getElementById('tension-meter-styles');
  if (!existingStyle) {
    const styleSheet = document.createElement('style');
    styleSheet.id = 'tension-meter-styles';
    styleSheet.textContent = styles;
    document.head.appendChild(styleSheet);
  }
}

