                  </span>
                )}
              </div>
            ))}
          </div>
        </Card>
      )}
    </div>
  );
};

/**
 * StorySelector Component
 *
 * Modal for selecting and starting stories.
 * Shows available stories for the current character with progress indicators.
 */
import { useState, useEffect } from 'react';
import { BookOpen, CheckCircle, PlayCircle, X, Sparkles } from 'lucide-react';
import { storyService } from '@/services/storyService';
import type { Story } from '@/types/story';

interface StorySelectorProps {
  characterId: string;
  sessionId: string | null;
  onSelectStory: (story: Story) => void;
  isOpen: boolean;
  onClose: () => void;
}

export function StorySelector({
  characterId,
  sessionId,
  onSelectStory,
  isOpen,
  onClose
}: StorySelectorProps) {
  const [stories, setStories] = useState<Story[]>([]);
  const [loading, setLoading] = useState(true);
  const [startingStoryId, setStartingStoryId] = useState<string | null>(null);

  useEffect(() => {
    if (isOpen && characterId) {
      loadStories();
    }
  }, [isOpen, characterId]);

  const loadStories = async () => {
    setLoading(true);
    try {
      const data = await storyService.getAvailableStories(characterId);
      setStories(data);
    } catch (error) {
      console.error('Failed to load stories:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleStartStory = async (story: Story) => {
    if (!sessionId) return;

    setStartingStoryId(story.id);
    try {
      await storyService.startStory(story.id, sessionId);
      onSelectStory(story);
      onClose();
    } catch (error) {
      console.error('Failed to start story:', error);
    } finally {
      setStartingStoryId(null);
    }
  };

  const handleResumeStory = async (story: Story) => {
    if (!sessionId) return;

    setStartingStoryId(story.id);
    try {
      await storyService.resumeStory(story.id, sessionId);
      onSelectStory(story);
      onClose();
    } catch (error) {
      console.error('Failed to resume story:', error);
    } finally {
      setStartingStoryId(null);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 p-4">
      <div className="bg-zinc-900 rounded-xl w-full max-w-2xl max-h-[80vh] overflow-hidden shadow-2xl border border-zinc-800">
        {/* Header */}
        <div className="p-4 border-b border-zinc-800 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <BookOpen className="text-purple-400" size={20} />
            <h2 className="text-xl font-bold text-white">Stories</h2>
          </div>
          <button
            onClick={onClose}
            className="text-zinc-400 hover:text-white p-1 rounded-lg hover:bg-zinc-800 transition-colors"
          >
            <X size={20} />
          </button>
        </div>

        {/* Content */}
        <div className="p-4 overflow-y-auto max-h-[60vh]">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-12">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-purple-500 mb-4" />
              <p className="text-zinc-400">Loading stories...</p>
            </div>
          ) : stories.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-12 text-center">
              <Sparkles className="text-zinc-600 mb-4" size={48} />
              <p className="text-zinc-400 mb-2">No stories available yet</p>
              <p className="text-zinc-500 text-sm">
                Keep chatting to unlock stories!
              </p>
            </div>
          ) : (
            <div className="grid gap-4">
              {stories.map(story => (
                <div
                  key={story.id}
                  className="bg-zinc-800/50 rounded-lg p-4 flex gap-4 hover:bg-zinc-800 transition-colors border border-zinc-700/50"
                >
                  {/* Cover Image */}
                  {story.cover_image_url ? (
                    <img
                      src={story.cover_image_url}
                      alt={story.title}
                      className="w-24 h-24 object-cover rounded-lg flex-shrink-0"
                    />
                  ) : (
                    <div className="w-24 h-24 bg-gradient-to-br from-purple-600/30 to-pink-600/30 rounded-lg flex-shrink-0 flex items-center justify-center">
                      <BookOpen className="text-purple-400" size={32} />
                    </div>
                  )}

                  {/* Story Info */}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1 flex-wrap">
                      <h3 className="font-semibold text-white truncate">{story.title}</h3>
                      {story.is_official && (
                        <span className="px-2 py-0.5 bg-purple-500/20 text-purple-400 text-xs rounded flex-shrink-0">
                          Official
                        </span>
                      )}
                    </div>
                    <p className="text-sm text-zinc-400 mb-3 line-clamp-2">
                      {story.description || 'No description'}
                    </p>

                    <div className="flex items-center justify-between gap-2 flex-wrap">
                      <div className="text-xs text-zinc-500">
                        {story.total_nodes} scenes
                      </div>

                      {story.user_progress?.status === 'completed' ? (
                        <span className="flex items-center gap-1 text-green-400 text-sm">
                          <CheckCircle size={16} />
                          Completed
                        </span>
                      ) : story.user_progress?.status === 'in_progress' ? (
                        <button
                          onClick={() => handleResumeStory(story)}
                          disabled={startingStoryId === story.id}
                          className="flex items-center gap-1 px-3 py-1.5 bg-purple-500 text-white rounded-lg text-sm hover:bg-purple-600 disabled:opacity-50 disabled:cursor-wait transition-colors"
                        >
                          {startingStoryId === story.id ? (
                            <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                          ) : (
                            <PlayCircle size={16} />
                          )}
                          Resume ({Math.round(story.user_progress.completion_percentage || 0)}%)
                        </button>
                      ) : (
                        <button
                          onClick={() => handleStartStory(story)}
                          disabled={startingStoryId === story.id}
                          className="flex items-center gap-1 px-3 py-1.5 bg-purple-500 text-white rounded-lg text-sm hover:bg-purple-600 disabled:opacity-50 disabled:cursor-wait transition-colors"
                        >
                          {startingStoryId === story.id ? (
                            <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                          ) : (
                            <PlayCircle size={16} />
                          )}
                          Start Story
                        </button>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="p-4 border-t border-zinc-800 bg-zinc-900/50">
          <p className="text-xs text-zinc-500 text-center">
            Stories unlock based on your relationship with the character
          </p>
        </div>
      </div>
    </div>
  );
}

﻿/**
 * Realtime Voice Call Component
 * 
 * v3.1 features:
 * - WebSocket connection
 * - Voice input/output
 * - Realtime TTS playback
 */

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Button } from '../common/Button';

interface RealtimeVoiceCallProps {
  characterId: string;
  characterName: string;
  characterAvatar?: string;
  onClose: () => void;
  onMessage?: (message: string, isUser: boolean) => void;
}

type ConnectionState = 'disconnected' | 'connecting' | 'connected' | 'error';

export const RealtimeVoiceCall: React.FC<RealtimeVoiceCallProps> = ({
  characterId,
  characterName,
  characterAvatar,
  onClose,
  onMessage,
}) => {
  const [connectionState, setConnectionState] = useState<ConnectionState>('disconnected');
  const [isMuted, setIsMuted] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [callDuration, setCallDuration] = useState(0);
  const [error, setError] = useState<string | null>(null);
  
  const wsRef = useRef<WebSocket | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioQueueRef = useRef<AudioBuffer[]>([]);
  const timerRef = useRef<NodeJS.Timeout | null>(null);
  
  // Format call duration
  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };
  
  // Connect WebSocket
  const connect = useCallback(async () => {
    setConnectionState('connecting');
    setError(null);
    
    try {
      // Get API base URL
      const baseUrl = import.meta.env.VITE_API_URL || 'http://localhost:8999';
      const wsUrl = baseUrl.replace('http', 'ws') + `/api/ws/voice/realtime/${characterId}`;
      
      const ws = new WebSocket(wsUrl);
      wsRef.current = ws;
      
      ws.onopen = () => {
        setConnectionState('connected');
        
        // Start timer
        timerRef.current = setInterval(() => {
          setCallDuration(prev => prev + 1);
        }, 1000);
        
        // Send init message
        ws.send(JSON.stringify({
          action: 'init',
          char_id: characterId,
        }));
      };
      
      ws.onmessage = async (event) => {
        try {
          const data = JSON.parse(event.data);
          
          switch (data.action) {
            case 'audio_chunk':
              // Play audio chunk
              await playAudioChunk(data.data);
              break;
              
            case 'text_response':
              // Received text response
              onMessage?.(data.text, false);
              break;
              
            case 'error':
              setError(data.message || 'Call error');
              break;
              
            case 'pong':
              // Heartbeat response
              break;
          }
        } catch (err) {
          console.error('Failed to parse message:', err);
        }
      };
      
      ws.onerror = (err) => {
        console.error('WebSocket error:', err);
        setError('Connection error');
        setConnectionState('error');
      };
      
      ws.onclose = () => {
        setConnectionState('disconnected');
        if (timerRef.current) {
          clearInterval(timerRef.current);
        }
      };
      
      // Initialize audio context
      audioContextRef.current = new AudioContext();
      
    } catch (err) {
      console.error('Connection failed:', err);
      setError('Connection failed');
      setConnectionState('error');
    }
  }, [characterId, onMessage]);
  
  // Disconnect
  const disconnect = useCallback(() => {
    if (wsRef.current) {
      wsRef.current.close();
      wsRef.current = null;
    }
    
    if (timerRef.current) {
      clearInterval(timerRef.current);
      timerRef.current = null;
    }
    
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
    }
    
    setConnectionState('disconnected');
    setCallDuration(0);
  }, []);
  
  // Play audio chunk
  const playAudioChunk = async (base64Data: string) => {
    if (!audioContextRef.current) return;
    
    try {
      // Decode Base64
      const binaryString = atob(base64Data);
      const bytes = new Uint8Array(binaryString.length);
      for (let i = 0; i < binaryString.length; i++) {
        bytes[i] = binaryString.charCodeAt(i);
      }
      
      // Decode audio
      const audioBuffer = await audioContextRef.current.decodeAudioData(bytes.buffer);
      
      // Create audio source and play
      const source = audioContextRef.current.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContextRef.current.destination);
      source.start();
    } catch (err) {
      console.error('Failed to play audio:', err);
    }
  };
  
  // Start recording
  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      
      const mediaRecorder = new MediaRecorder(stream, {
        mimeType: 'audio/webm;codecs=opus',
      });
      
      mediaRecorderRef.current = mediaRecorder;
      
      const chunks: Blob[] = [];
      
      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          chunks.push(event.data);
        }
      };
      
      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(chunks, { type: 'audio/webm' });
        
        // Convert to Base64 and send
        const reader = new FileReader();
        reader.onloadend = () => {
          const base64 = (reader.result as string).split(',')[1];
          
          if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
            wsRef.current.send(JSON.stringify({
              action: 'audio_input',
              data: base64,
              format: 'webm',
            }));
          }
        };
        reader.readAsDataURL(audioBlob);
        
        // Stop all tracks
        stream.getTracks().forEach(track => track.stop());
      };
      
      mediaRecorder.start();
      setIsRecording(true);
      
    } catch (err) {
      console.error('Failed to start recording:', err);
      setError('Cannot access microphone');
    }
  };
  
  // Stop recording
  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
    }
    setIsRecording(false);
  };
  
  // Send text message
  const sendTextMessage = (text: string) => {
    if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({
        action: 'text_input',
        text,
      }));
      
      onMessage?.(text, true);
    }
  };
  
  // Cleanup
  useEffect(() => {
    return () => {
      disconnect();
    };
  }, [disconnect]);
  
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80">
      <div className="w-full max-w-md mx-4">
        {/* Call UI */}
        <div className="bg-gradient-to-b from-gray-900 to-gray-800 rounded-3xl overflow-hidden shadow-2xl">
          {/* Header */}
          <div className="p-6 text-center">
            {/* Character avatar */}
            <div className="relative mx-auto w-32 h-32 mb-4">
              <div className={`w-full h-full rounded-full overflow-hidden border-4 ${
                connectionState === 'connected' ? 'border-green-500' : 'border-gray-600'
              }`}>
                {characterAvatar ? (
                  <img 
                    src={characterAvatar} 
                    alt={characterName}
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <div className="w-full h-full bg-gradient-to-br from-purple-500 to-pink-500 flex items-center justify-center text-white text-4xl font-bold">
                    {characterName.charAt(0)}
                  </div>
                )}
              </div>
              
              {/* Connection status indicator */}
              {connectionState === 'connected' && (
                <div className="absolute -bottom-1 -right-1 w-6 h-6 bg-green-500 rounded-full border-4 border-gray-900 animate-pulse" />
              )}
            </div>
            
            {/* Character name */}
            <h2 className="text-xl font-bold text-white">{characterName}</h2>
            
            {/* Status text */}
            <p className="text-gray-400 mt-1">
              {connectionState === 'disconnected' && 'Ready to call'}
              {connectionState === 'connecting' && 'Connecting...'}
              {connectionState === 'connected' && formatDuration(callDuration)}
              {connectionState === 'error' && (error || 'Connection failed')}
            </p>
          </div>
          
          {/* Wave animation (shown during call) */}
          {connectionState === 'connected' && (
            <div className="flex justify-center items-center gap-1 h-16 px-6">
              {[...Array(20)].map((_, i) => (
                <div
                  key={i}
                  className="w-1 bg-purple-500 rounded-full animate-pulse"
                  style={{
                    height: `${Math.random() * 100}%`,
                    animationDelay: `${i * 0.05}s`,
                  }}
                />
              ))}
            </div>
          )}
          
          {/* Control buttons */}
          <div className="p-6 flex justify-center items-center gap-6">
            {connectionState === 'disconnected' ? (
              // Disconnected state - show call button
              <button
                onClick={connect}
                className="w-16 h-16 bg-green-500 hover:bg-green-600 rounded-full flex items-center justify-center text-white transition-colors"
              >
                <svg className="w-8 h-8" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M6.62 10.79c1.44 2.83 3.76 5.14 6.59 6.59l2.2-2.2c.27-.27.67-.36 1.02-.24 1.12.37 2.33.57 3.57.57.55 0 1 .45 1 1V20c0 .55-.45 1-1 1-9.39 0-17-7.61-17-17 0-.55.45-1 1-1h3.5c.55 0 1 .45 1 1 0 1.25.2 2.45.57 3.57.11.35.03.74-.25 1.02l-2.2 2.2z"/>
                </svg>
              </button>
            ) : connectionState === 'connecting' ? (
              // Connecting
              <div className="w-16 h-16 bg-yellow-500 rounded-full flex items-center justify-center animate-pulse">
                <svg className="w-8 h-8 text-white animate-spin" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"/>
                </svg>
              </div>
            ) : (
              // Connected - show control buttons
              <>
                {/* Mute button */}
                <button
                  onClick={() => setIsMuted(!isMuted)}
                  className={`w-12 h-12 rounded-full flex items-center justify-center transition-colors ${
                    isMuted ? 'bg-red-500 text-white' : 'bg-gray-700 text-gray-300 hover:bg-gray-600'
                  }`}
                >
                  {isMuted ? (
                    <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24">
                      <path d="M16.5 12c0-1.77-1.02-3.29-2.5-4.03v2.21l2.45 2.45c.03-.2.05-.41.05-.63zm2.5 0c0 .94-.2 1.82-.54 2.64l1.51 1.51C20.63 14.91 21 13.5 21 12c0-4.28-2.99-7.86-7-8.77v2.06c2.89.86 5 3.54 5 6.71zM4.27 3L3 4.27 7.73 9H3v6h4l5 5v-6.73l4.25 4.25c-.67.52-1.42.93-2.25 1.18v2.06c1.38-.31 2.63-.95 3.69-1.81L19.73 21 21 19.73l-9-9L4.27 3zM12 4L9.91 6.09 12 8.18V4z"/>
                    </svg>
                  ) : (
                    <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24">
                      <path d="M3 9v6h4l5 5V4L7 9H3zm13.5 3c0-1.77-1.02-3.29-2.5-4.03v8.05c1.48-.73 2.5-2.25 2.5-4.02zM14 3.23v2.06c2.89.86 5 3.54 5 6.71s-2.11 5.85-5 6.71v2.06c4.01-.91 7-4.49 7-8.77s-2.99-7.86-7-8.77z"/>
                    </svg>
                  )}
                </button>
                
                {/* Record button */}
                <button
                  onMouseDown={startRecording}
                  onMouseUp={stopRecording}
                  onTouchStart={startRecording}
                  onTouchEnd={stopRecording}
                  className={`w-16 h-16 rounded-full flex items-center justify-center transition-colors ${
                    isRecording 
                      ? 'bg-red-500 animate-pulse' 
                      : 'bg-purple-600 hover:bg-purple-700'
                  }`}
                >
                  <svg className="w-8 h-8 text-white" fill="currentColor" viewBox="0 0 24 24">
                    <path d="M12 14c1.66 0 2.99-1.34 2.99-3L15 5c0-1.66-1.34-3-3-3S9 3.34 9 5v6c0 1.66 1.34 3 3 3zm5.3-3c0 3-2.54 5.1-5.3 5.1S6.7 14 6.7 11H5c0 3.41 2.72 6.23 6 6.72V21h2v-3.28c3.28-.48 6-3.3 6-6.72h-1.7z"/>
                  </svg>
                </button>
                
                {/* Hang-up button */}
                <button
                  onClick={() => {
                    disconnect();
                    onClose();
                  }}
                  className="w-12 h-12 bg-red-500 hover:bg-red-600 rounded-full flex items-center justify-center text-white transition-colors"
                >
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24">
                    <path d="M12 9c-1.6 0-3.15.25-4.6.72v3.1c0 .39-.23.74-.56.9-.98.49-1.87 1.12-2.66 1.85-.18.18-.43.28-.7.28-.28 0-.53-.11-.71-.29L.29 13.08c-.18-.17-.29-.42-.29-.7 0-.28.11-.53.29-.71C3.34 8.78 7.46 7 12 7s8.66 1.78 11.71 4.67c.18.18.29.43.29.71 0 .28-.11.53-.29.71l-2.48 2.48c-.18.18-.43.29-.71.29-.27 0-.52-.11-.7-.28-.79-.74-1.69-1.36-2.67-1.85-.33-.16-.56-.5-.56-.9v-3.1C15.15 9.25 13.6 9 12 9z"/>
                  </svg>
                </button>
              </>
            )}
          </div>
          
          {/* Hint text */}
          {connectionState === 'connected' && (
            <p className="text-center text-gray-500 text-sm pb-4">
              Hold the microphone button to speak
            </p>
          )}
        </div>
        
        {/* Close button */}
        {connectionState === 'disconnected' && (
          <button
            onClick={onClose}
            className="w-full mt-4 py-3 text-gray-400 hover:text-white transition-colors"
          >
            Cancel
          </button>
        )}
      </div>
    </div>
  );
};

