import { createContext, useContext, useEffect, useState, useCallback } from 'react';
import {
  isAgeVerified,
  setAgeVerified,
  isBlocked,
  setBlocked,
  getBlockTimeRemaining,
  clearBlocked
} from '@/utils/ageGateStorage';

interface AgeGateContextType {
  /** Whether user has passed age verification */
  isVerified: boolean;
  /** Whether user is blocked (clicked "I am under 18") */
  isUserBlocked: boolean;
  /** Remaining block time in milliseconds */
  blockTimeRemaining: number;
  /** Loading state during initialization */
  loading: boolean;
  /** Mark user as verified (18+) */
  verify: () => void;
  /** Block user (under 18) */
  block: () => void;
}

const AgeGateContext = createContext<AgeGateContextType | undefined>(undefined);

export function AgeGateProvider({ children }: { children: React.ReactNode }) {
  const [isVerified, setIsVerified] = useState(false);
  const [isUserBlocked, setIsUserBlocked] = useState(false);
  const [blockTimeRemaining, setBlockTimeRemaining] = useState(0);
  const [loading, setLoading] = useState(true);

  // Initialize state from storage
  useEffect(() => {
    const verified = isAgeVerified();
    const blocked = isBlocked();
    const blockTime = getBlockTimeRemaining();

    setIsVerified(verified);
    setIsUserBlocked(blocked);
    setBlockTimeRemaining(blockTime);
    setLoading(false);
  }, []);

  // Update block time remaining periodically
  useEffect(() => {
    if (!isUserBlocked) return;

    const interval = setInterval(() => {
      const remaining = getBlockTimeRemaining();
      setBlockTimeRemaining(remaining);

      if (remaining <= 0) {
        clearBlocked();
        setIsUserBlocked(false);
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [isUserBlocked]);

  const verify = useCallback(() => {
    setAgeVerified();
    setIsVerified(true);
  }, []);

  const block = useCallback(() => {
    setBlocked();
    setIsUserBlocked(true);
    setBlockTimeRemaining(getBlockTimeRemaining());
  }, []);

  return (
    <AgeGateContext.Provider
      value={{
        isVerified,
        isUserBlocked,
        blockTimeRemaining,
        loading,
        verify,
        block
      }}
    >
      {children}
    </AgeGateContext.Provider>
  );
}

export function useAgeGate(): AgeGateContextType {
  const context = useContext(AgeGateContext);
  if (context === undefined) {
    throw new Error('useAgeGate must be used within an AgeGateProvider');
  }
  return context;
}

import { createContext, useContext, useEffect, useState } from 'react';
import type { User as FirebaseUser } from 'firebase/auth';
import { auth } from '@/config/firebase';
import { authService } from '@/services/authService';
import type { User as AppUser } from '@/types';

interface AuthContextType {
  user: AppUser | null;
  firebaseUser: FirebaseUser | null;
  loading: boolean;
  isAuthenticated: boolean;
  login: (email: string, password: string) => Promise<void>;
  loginWithGoogle: () => Promise<void>;
  register: (email: string, password: string, captchaToken?: string | null) => Promise<void>;
  completeRegistration: (dateOfBirth: { month: number; day: number; year: number }, ageConsent: boolean) => Promise<void>;
  logout: () => Promise<void>;
  refreshUser: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [firebaseUser, setFirebaseUser] = useState<FirebaseUser | null>(null);
  const [user, setUser] = useState<AppUser | null>(null);
  const [loading, setLoading] = useState(true);

  const refreshUser = async () => {
    if (auth.currentUser) {
      try {
        const userData = await authService.getCurrentUser();
        setUser(userData);
      } catch (error) {
        console.error('Error refreshing user data:', error);
      }
    }
  };

  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged(async (firebaseUser) => {
      setFirebaseUser(firebaseUser);

      if (firebaseUser) {
        try {
          const userData = await authService.getCurrentUser();
          setUser(userData);

          // Daily Check-in
          try {
            const checkinResult = await authService.checkin();
            if (checkinResult && checkinResult.success) {
              console.log('Daily check-in successful:', checkinResult.message);
              // Update credits in state
              setUser(prev => prev ? { ...prev, credits: checkinResult.new_balance } : prev);
            }
          } catch (e) {
            console.error('Check-in check failed (silent)', e);
          }
        } catch (error) {
          console.error('Error fetching user data:', error);
          setUser(null);
        }
      } else {
        setUser(null);
      }

      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const login = async (email: string, password: string) => {
    setLoading(true);
    try {
      await authService.login(email, password);
    } catch (error: unknown) {
      const code = (error as { code?: string }).code;
      if (code === 'auth/network-request-failed') {
        try {
          await authService.getCurrentUser();
        } catch {}
        setLoading(false);
        return;
      }
      setLoading(false);
      throw error;
    }
  };

  const loginWithGoogle = async () => {
    setLoading(true);
    try {
      await authService.loginWithGoogle();
    } catch (error) {
      setLoading(false);
      throw error;
    }
  };

  const register = async (email: string, password: string, captchaToken?: string | null) => {
    setLoading(true);
    try {
      // Use new email verification flow - doesn't create Firebase account yet
      await authService.initiateRegistration(email, password, captchaToken);
    } catch (error) {
      throw error;
    } finally {
      setLoading(false);
    }
  };

  const completeRegistration = async (dateOfBirth: { month: number; day: number; year: number }, ageConsent: boolean) => {
    setLoading(true);
    try {
      const updatedUser = await authService.completeRegistration(dateOfBirth, ageConsent);
      setUser(updatedUser);
    } finally {
      setLoading(false);
    }
  };

  const logout = async () => {
    setLoading(true);
    try {
      await authService.logout();
      setUser(null);
      setFirebaseUser(null);
    } finally {
      setLoading(false);
    }
  };

  const value = {
    user,
    firebaseUser,
    loading,
    isAuthenticated: !!user,
    login,
    loginWithGoogle,
    register,
    completeRegistration,
    logout,
    refreshUser,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  } 
  return context;
}

