import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Container } from '@/components/layout';
import { Button, Card } from '@/components/common';
import { CharacterWizardProvider, useWizard } from '@/contexts/CharacterWizardContext';
import { WizardProgress, WizardNavigation } from '@/components/character';
import {
  Step1StyleSelection,
  Step2TemplateSelection,
  Step3Relationship,
  Step4Appearance,
  Step5Personality,
  Step6Voice,
  Step7BackgroundBoundaries,
  Step8SceneOpening,
  Step9Confirm,
} from '@/components/character/steps';
import { Shuffle, RotateCcw, Download, Upload } from 'lucide-react';
import { api } from '@/services/api';

function CreateCharacterContent() {
  const navigate = useNavigate();
  const { currentStep, characterData, randomizeAll, resetWizard, updateField, updateNestedField } = useWizard();
  const [creating, setCreating] = useState(false);
  const [error, setError] = useState('');

  const handleExportCard = () => {
    const cardData = {
      spec: 'aigirl_character_card',
      spec_version: '1.2',
      data: {
        name: characterData.identity.firstName || 'Unnamed',
        description: `${characterData.identity.age || 18} year old ${characterData.gender}`,
        template: characterData.template,
        gender: characterData.gender,
        style: characterData.style,
        relation: characterData.relation,
        appearance: characterData.appearance,
        hair: characterData.hair,
        face: characterData.face,
        outfit: characterData.outfit,
        background: characterData.background,
        personality: {
          tags: characterData.personality.tags,
          relationship: characterData.personality.relationship,
          summary: characterData.personalitySummary,
          example: characterData.personalityExample,
        },
        preferences: characterData.preferences,
        chatRules: characterData.chatRules,
        scene: characterData.scene,
        voiceProfile: characterData.voiceProfile,
        avatarUrl: characterData.avatarUrl,
        identity: characterData.identity,
      },
    };

    const blob = new Blob([JSON.stringify(cardData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${characterData.identity.firstName || 'character'}_card.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleImportCard = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const cardData = JSON.parse(e.target?.result as string);
        if (cardData.spec !== 'aigirl_character_card') {
          setError('Invalid character card format');
          return;
        }

        const data = cardData.data || {};
        if (data.template) updateField('template', data.template);
        if (data.gender) updateField('gender', data.gender);
        if (data.style) updateField('style', data.style);
        if (data.relation) updateNestedField('relation', data.relation);
        if (data.appearance) updateNestedField('appearance', data.appearance);
        if (data.hair) updateNestedField('hair', data.hair);
        if (data.face) updateNestedField('face', data.face);
        if (data.outfit) updateNestedField('outfit', data.outfit);
        if (data.background) updateNestedField('background', data.background);

        if (typeof data.personality === 'string') {
          updateField('personality', { tags: data.personality.split(', '), relationship: 'Friend' });
        } else if (data.personality) {
          if (data.personality.tags) updateNestedField('personality.tags', data.personality.tags);
          if (data.personality.relationship) updateNestedField('personality.relationship', data.personality.relationship);
          if (data.personality.summary) updateField('personalitySummary', data.personality.summary);
          if (data.personality.example) updateField('personalityExample', data.personality.example);
        }

        if (data.preferences) updateField('preferences', data.preferences);
        if (data.chatRules) updateField('chatRules', data.chatRules);
        if (data.scene) updateField('scene', data.scene);
        if (data.voiceProfile) updateField('voiceProfile', data.voiceProfile);
        if (data.avatarUrl) updateField('avatarUrl', data.avatarUrl);
        if (data.name) updateNestedField('identity.firstName', data.name);
        if (data.identity) updateField('identity', data.identity);

        setError('');
        alert('Character card imported successfully!');
      } catch (err) {
        console.error('Failed to import card:', err);
        setError('Failed to parse character card file');
      }
    };
    reader.readAsText(file);
  };

  const handleComplete = async () => {
    setError('');
    setCreating(true);

    try {
      const relationPayload =
        characterData.relation
          ? {
              ...characterData.relation,
              relationship_type: characterData.personality.relationship,
            }
          : characterData.personality.relationship
            ? { relationship_type: characterData.personality.relationship }
            : null;

      const characterPayload = {
        name: characterData.identity.firstName,
        gender: characterData.gender,
        style: characterData.style,
        base_info: {
          age: characterData.identity.age,
          race: characterData.identity.race || null,
          voice_profile: characterData.voiceProfile || null,
          appearance: {
            body_type: characterData.appearance.bodyType,
            skin_tone: characterData.appearance.skinTone,
            hair_style: characterData.hair.style,
            hair_color: characterData.hair.color,
            eye_color: characterData.face.eyeColor,
            lip_color: characterData.face.lipColor,
          },
          occupation: characterData.background.profession,
        },
        outfit: {
          style: characterData.outfit.style,
          description: characterData.outfit.description,
        },
        background: {
          occupation: characterData.background.profession,
          hobbies: characterData.background.hobbies,
          backstory: characterData.background.backstory,
        },
        personality_summary: characterData.personalitySummary || null,
        personality_example: characterData.personalityExample || null,
        preferences: characterData.preferences || null,
        chat_rules: characterData.chatRules || null,
        greeting: characterData.scene?.openingMessage || null,
        scene_preset: characterData.scene?.environment || null,
        template: characterData.template || null,
        avatar_url: characterData.avatarUrl || null,
        relation: relationPayload,
        personality_tags: characterData.personality.tags,
        relationship_role: characterData.relation?.character_role || null,
        user_role: characterData.relation?.user_role || null,
        consistency_config: characterData.consistency_config || null,
      };

      const response = await api.post('/characters', characterPayload);

      resetWizard();

      navigate(`/chat?character=${response.data.id}`);
    } catch (err: any) {
      console.error('Failed to create character:', err);
      const detail = err.response?.data?.detail;
      if (Array.isArray(detail)) {
        const messages = detail.map((e: any) => e.msg || e.message || 'Validation error').join('; ');
        setError(messages || 'Validation failed. Please check your input.');
      } else if (typeof detail === 'string') {
        setError(detail);
      } else {
        setError('Failed to create character. Please try again.');
      }
    } finally {
      setCreating(false);
    }
  };

  const renderStep = () => {
    switch (currentStep) {
      case 1:
        return <Step1StyleSelection />;
      case 2:
        return <Step2TemplateSelection />;
      case 3:
        return <Step3Relationship />;
      case 4:
        return <Step4Appearance />;
      case 5:
        return <Step5Personality />;
      case 6:
        return <Step6Voice />;
      case 7:
        return <Step7BackgroundBoundaries />;
      case 8:
        return <Step8SceneOpening />;
      case 9:
        return <Step9Confirm />;
      default:
        return <Step1StyleSelection />;
    }
  };

  return (
    <div className="min-h-screen py-8">
      <Container>
        <div className="text-center mb-8">
          <h1 className="text-4xl md:text-5xl font-heading font-bold mb-4">
            Create Your <span className="gradient-text">AI Character</span>
          </h1>
          <p className="text-xl text-zinc-400">
            Design every detail of your perfect AI companion
          </p>
        </div>

        <div className="flex justify-center flex-wrap gap-4 mb-8">
          <Button
            variant="outline"
            size="sm"
            onClick={randomizeAll}
            className="flex items-center gap-2"
          >
            <Shuffle size={16} />
            Randomize All
          </Button>
          <Button
            variant="ghost"
            size="sm"
            onClick={resetWizard}
            className="flex items-center gap-2"
          >
            <RotateCcw size={16} />
            Start Over
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={handleExportCard}
            className="flex items-center gap-2"
          >
            <Download size={16} />
            Export Card
          </Button>
          <label>
            <Button
              variant="outline"
              size="sm"
              className="flex items-center gap-2 cursor-pointer"
              as="span"
            >
              <Upload size={16} />
              Import Card
            </Button>
            <input
              type="file"
              accept=".json"
              onChange={handleImportCard}
              className="hidden"
            />
          </label>
        </div>

        <WizardProgress />

        {error && (
          <div className="max-w-4xl mx-auto mb-8">
            <Card className="bg-red-500/10 border-red-500/50">
              <p className="text-red-500">{error}</p>
            </Card>
          </div>
        )}

        <div className="mb-8">{renderStep()}</div>

        <div className="max-w-4xl mx-auto">
          <WizardNavigation onComplete={handleComplete} />
        </div>

        {creating && (
          <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-50">
            <Card glass className="text-center space-y-4 max-w-md">
              <div className="w-16 h-16 border-4 border-primary-500 border-t-transparent rounded-full animate-spin mx-auto"></div>
              <h3 className="text-xl font-semibold">Creating Your Character...</h3>
              <p className="text-zinc-400">
                Generating unique AI personality and appearance
              </p>
              <p className="text-sm text-zinc-500">This may take 20-30 seconds</p>
            </Card>
          </div>
        )}
      </Container>
    </div>
  );
}

export function CreateCharacterPage() {
  return (
    <CharacterWizardProvider>
      <CreateCharacterContent />
    </CharacterWizardProvider>
  );
}

